package com.user.servlet; import javax.servlet.annotation.WebServlet; import javax.servlet.http.*; import java.io.*; @WebServlet("/logout") public class LogoutServlet extends HttpServlet {protected void doGet(HttpServletRequest r,HttpServletResponse p)throws IOException{r.getSession().invalidate();p.sendRedirect("login.jsp");} protected void doPost(HttpServletRequest r,HttpServletResponse p)throws IOException{doGet(r,p);}}
